#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>

// Constants for SELU
constexpr float ALPHA = 1.6732632423543772848170429916717f;
constexpr float SCALE = 1.0507009873554804934193349852946f;
constexpr float LAMBDA = 1.0507009873554804934193349852946f;
constexpr float NEG_ALPHA_LAMBDA = -1.7580993408473768599402175208123f;

// Unified computation function to ensure consistency across all types
__device__ __forceinline__ float selu_compute_float(float x) {
    // Using explicit multiplication for clarity and consistency
    // All arithmetic operators are in this single function
    return (x >= 0.0f) ? (SCALE * x) : (LAMBDA * (ALPHA * expf(x) - ALPHA));
}

// Half specialization using the same mathematical formula
template<>
__device__ __forceinline__ half selu_compute<half>(half x) {
    float fx = __half2float(x);
    float result = selu_compute_float(fx);
    return __float2half(result);
}

// Generic template now uses the unified computation via float conversion
// This ensures all paths use the same mathematical operations
template<typename T>
__device__ __forceinline__ T selu_compute(T x) {
    // Convert to float, compute using unified function, convert back
    float fx = static_cast<float>(x);
    float result = selu_compute_float(fx);
    return static_cast<T>(result);
}

// Specialized kernel for float32 that uses the unified computation function
__global__ void selu_kernel_float32(const float* __restrict__ input, float* __restrict__ output, int64_t size) {
    const int64_t idx = (blockIdx.x * blockDim.x + threadIdx.x);

    // Process 4 elements per thread with vectorized loads/stores
    if (idx * 4 + 3 < size) {
        // Load 4 floats at once
        float4 in = *reinterpret_cast<const float4*>(&input[idx * 4]);

        // Compute SELU using the unified function
        float4 out;
        out.x = selu_compute_float(in.x);
        out.y = selu_compute_float(in.y);
        out.z = selu_compute_float(in.z);
        out.w = selu_compute_float(in.w);

        // Store 4 floats at once
        *reinterpret_cast<float4*>(&output[idx * 4]) = out;
    } else {
        // Handle remaining elements
        for (int64_t i = idx * 4; i < size; i++) {
            output[i] = selu_compute_float(input[i]);
        }
    }
}

// Generic kernel that works for all floating types
// Uses the same computation path for consistency
template<typename T>
__global__ void selu_kernel_generic(const T* __restrict__ input, T* __restrict__ output, int64_t size) {
    // Process 8 elements per thread for better occupancy
    const int64_t idx = (blockIdx.x * blockDim.x + threadIdx.x) * 8;

    #pragma unroll
